  fn: () => Promise<PollResult>,
  interval?: number,
  timeout?: number,
) => Promise<PollResult>; // 轮询函数，fn为异步函数，interval为轮询间隔，timeout为超时时间，返回fn的结果
declare const createOpenAI: any;
